def arrays_isomorphic(a, b):
    if len(a) != len(b):
        return False
    map_ab = {}
    map_ba = {}
    for x, y in zip(a, b):
        if x in map_ab and map_ab[x] != y:
            return False
        if y in map_ba and map_ba[y] != x:
            return False
        map_ab[x] = y
        map_ba[y] = x
    return True

